// Le Merge par position combine les items : item 0 contient les deux sources
const data = items[0].json;

// Extraire la citation (zenquotes retourne un tableau dans le merge)
let quote = 'Citation indisponible';
let author = 'Inconnu';

// Chercher les champs de citation dans les donnees mergees
if (data.q) {
  quote = data.q;
  author = data.a || author;
} else if (Array.isArray(data)) {
  quote = data[0]?.q || quote;
  author = data[0]?.a || author;
}

// Chercher dans tous les items au cas ou
for (const item of items) {
  const d = item.json;
  if (d.q && quote === 'Citation indisponible') {
    quote = d.q;
    author = d.a || author;
  }
}

// Extraire la meteo (Open-Meteo format)
let temperature = 'N/A';
let weatherCode = 0;

if (data.current) {
  temperature = Math.round(data.current.temperature_2m);
  weatherCode = data.current.weather_code || 0;
} else {
  // Chercher dans tous les items
  for (const item of items) {
    if (item.json.current) {
      temperature = Math.round(item.json.current.temperature_2m);
      weatherCode = item.json.current.weather_code || 0;
      break;
    }
  }
}

// Convertir weather_code WMO en description
const weatherDescriptions = {
  0: 'ciel degage', 1: 'peu nuageux', 2: 'partiellement nuageux', 3: 'couvert',
  45: 'brouillard', 48: 'brouillard givrant',
  51: 'bruine legere', 53: 'bruine', 55: 'bruine forte',
  61: 'pluie legere', 63: 'pluie', 65: 'pluie forte',
  71: 'neige legere', 73: 'neige', 75: 'neige forte',
  80: 'averses legeres', 81: 'averses', 82: 'averses fortes',
  95: 'orage', 96: 'orage avec grele'
};
const condition = weatherDescriptions[weatherCode] || 'inconnu';

// Construire le briefing
const now = new Date();
const dateStr = now.toLocaleDateString('fr-FR', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

return [{
  json: {
    briefing: {
      date: dateStr,
      meteo: {
        ville: 'Paris',
        temperature: `${temperature}°C`,
        condition: condition,
        code_wmo: weatherCode
      },
      citation: {
        texte: quote,
        auteur: author
      },
      message: `Bonjour ! Il fait ${temperature}°C a Paris (${condition}). Citation du jour : \"${quote}\" - ${author}`
    }
  }
}];
